-- =============================================================
-- 130_storage_assets.sql  (LOCAL UPLOAD ASSETS)
-- Ensotek - All images from backend/uploads/ directory
-- Total: 216 assets
-- Generated: 2026-03-23
-- =============================================================

SET NAMES utf8mb4;
SET time_zone = '+00:00';
SET FOREIGN_KEY_CHECKS = 0;

START TRANSACTION;

ON DUPLICATE KEY UPDATE
  name = VALUES(name),
  mime = VALUES(mime),
  size = VALUES(size),
  url = VALUES(url),
  updated_at = VALUES(updated_at);

COMMIT;
SET FOREIGN_KEY_CHECKS = 1;
